          key="business" 
        />
        <TabPane 
          tab={
            <span>
              <SearchOutlined />
              自定义指标
            </span>
          } 
          key="custom" 
        />
      </Tabs>

      <div style={{ marginTop: 16 }}>
        {renderTabContent()}
      </div>
    </div>
  );
};

export default Monitoring;

